import { AdminShell, useAdminAuth } from "@/components/admin/admin-layout"
import { useState, useEffect } from "react"
import Link from "next/link"
import {
  PageHeader, SearchInput, StatCard, Badge,
  CardSkeleton, EmptyState,
} from "@/components/admin/ui"

const statusColors: Record<string, string> = {
  pendiente: "bg-yellow-500/10 text-yellow-400 border-yellow-500/20",
  confirmado: "bg-blue-500/10 text-blue-400 border-blue-500/20",
  enviado: "bg-purple-500/10 text-purple-400 border-purple-500/20",
  entregado: "bg-emerald-500/10 text-emerald-400 border-emerald-500/20",
  cancelado: "bg-red-500/10 text-red-400 border-red-500/20",
}

export default function AdminCustomerHistory() {
  const { authed } = useAdminAuth()
  const [profiles, setProfiles] = useState<any[]>([])
  const [selected, setSelected] = useState<string | null>(null)
  const [orders, setOrders] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [customersLoading, setCustomersLoading] = useState(true)
  const [search, setSearch] = useState("")

  useEffect(() => {
    if (!authed) return
    setCustomersLoading(true)
    fetch("/api/admin/customers").then(r => r.json()).then(data => {
      if (Array.isArray(data)) setProfiles(data)
      setCustomersLoading(false)
      setLoading(false)
    })
  }, [authed])

  useEffect(() => {
    if (!selected) return
    setLoading(true)
    fetch("/api/admin/orders").then(r => r.json()).then(data => {
      if (Array.isArray(data)) setOrders(data.filter((o: any) => o.user_id === selected))
      setLoading(false)
    })
  }, [selected])

  if (!authed) return null

  const customer = profiles.find(p => p.id === selected)
  const totalSpent = orders.reduce((s, o) => {
    const n = parseInt((o.total || "0").replace(/[^0-9]/g, ""), 10) || 0
    return s + n
  }, 0)

  const filteredProfiles = search
    ? profiles.filter(p => (p.name || "").toLowerCase().includes(search.toLowerCase()) || (p.email || "").toLowerCase().includes(search.toLowerCase()))
    : profiles

  return (
    <>
      <PageHeader title="Historial de clientes" subtitle={`${profiles.length} clientes registrados`} />

      <div className="grid gap-6 lg:grid-cols-[340px_1fr]">
        {/* Customer list sidebar */}
        <div className="rounded-xl border border-zinc-800/60 bg-zinc-900/50 overflow-hidden">
          <div className="p-4 border-b border-zinc-800/60">
            <SearchInput value={search} onChange={setSearch} placeholder="Buscar cliente..." />
          </div>
          <div className="max-h-[700px] overflow-y-auto divide-y divide-zinc-800/60">
            {customersLoading ? (
              Array.from({ length: 6 }).map((_, i) => (
                <div key={i} className="animate-pulse p-4">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-full bg-zinc-800" />
                    <div className="flex-1">
                      <div className="h-4 w-32 rounded-md bg-zinc-800 mb-2" />
                      <div className="h-3 w-48 rounded-md bg-zinc-800" />
                    </div>
                  </div>
                </div>
              ))
            ) : filteredProfiles.length === 0 ? (
              <div className="flex flex-col items-center py-16 text-zinc-500">
                <svg className="w-10 h-10 mb-3 text-zinc-600" fill="none" viewBox="[REDACTED_PHONE]" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M17 20h5v-2a[REDACTED_PHONE].356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a[REDACTED_PHONE].356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.[REDACTED_PHONE].288 0M15 7a[REDACTED_PHONE]z" />
                </svg>
                <p className="text-sm text-zinc-500">{search ? "Sin resultados" : "Sin clientes"}</p>
              </div>
            ) : (
              filteredProfiles.map(p => (
                <button
                  key={p.id}
                  onClick={() => setSelected(p.id)}
                  className={`w-full text-left p-4 transition-all hover:bg-zinc-800/40 ${
                    selected === p.id ? "bg-emerald-600/10 border-l-2 border-emerald-500" : ""
                  }`}
                >
                  <div className="flex items-center gap-3">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold shrink-0 ${
                      selected === p.id ? "bg-emerald-600/20 text-emerald-400" : "bg-zinc-800 text-zinc-400"
                    }`}>
                      {(p.name || "?")[0].toUpperCase()}
                    </div>
                    <div className="min-w-0">
                      <p className="font-medium text-white text-sm truncate">{p.name || "Sin nombre"}</p>
                      <p className="text-xs text-zinc-500 truncate">{p.phone || p.email || "Sin contacto"}</p>
                    </div>
                  </div>
                </button>
              ))
            )}
          </div>
        </div>

        {/* Detail panel */}
        <div>
          {!selected ? (
            <EmptyState
              icon={
                <svg fill="none" viewBox="[REDACTED_PHONE]" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M17 20h5v-2a[REDACTED_PHONE].356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a[REDACTED_PHONE].356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.[REDACTED_PHONE].288 0M15 7a[REDACTED_PHONE]z" />
